// Data/ApplicationDbContext.cs
using Microsoft.EntityFrameworkCore;
using ProductReviews.Models;

namespace ProductReviews.Data
{
    public class ApplicationDbContext : DbContext
    {
        public ApplicationDbContext(DbContextOptions<ApplicationDbContext> options)
            : base(options)
        {
        }

        public DbSet<Product> Products { get; set; }
        public DbSet<Review> Reviews { get; set; }

        protected override void OnModelCreating(ModelBuilder modelBuilder)
        {
            base.OnModelCreating(modelBuilder);

            modelBuilder.Entity<Review>()
                .HasOne(r => r.Product)
                .WithMany(p => p.Reviews)
                .HasForeignKey(r => r.ProductId);

            modelBuilder.Entity<Product>().HasData(
                new Product { Id = 1, Name = "Sample Product", Description = "A great product", Price = 29.99m }
            );
        }
    }
}

// Helpers/ReviewFormattingHelper.cs
using System.Net;
using System.Text.RegularExpressions;

namespace ProductReviews.Helpers
{
    public static class ReviewFormattingHelper
    {
        /// <summary>
        /// Sanitizes user input and converts allowed formatting markers to HTML.
        /// Allowed formatting:
        ///   *bold text* => <strong>bold text</strong>
        ///   _italic text_ => <em>italic text</em>
        /// All other HTML is escaped to prevent XSS.
        /// </summary>
        public static string FormatReviewContent(string rawContent)
        {
            if (string.IsNullOrEmpty(rawContent))
                return string.Empty;

            // First, HTML-encode the entire content to prevent XSS
            string encoded = WebUtility.HtmlEncode(rawContent);

            // Convert newlines to <br> tags
            encoded = encoded.Replace("\r\n", "<br/>").Replace("\n", "<br/>");

            // Convert *text* to <strong>text</strong> (bold)
            encoded = Regex.Replace(encoded, @"\*(.+?)\*", "<strong>$1</strong>");

            // Convert _text_ to <em>text</em> (italic)
            encoded = Regex.Replace(encoded, @"_(.+?)_", "<em>$1</em>");

            return encoded;
        }
    }
}

// Controllers/ProductController.cs
using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using ProductReviews.Data;
using ProductReviews.Models;

namespace ProductReviews.Controllers
{
    public class ProductController : Controller
    {
        private readonly ApplicationDbContext _context;

        public ProductController(ApplicationDbContext context)
        {
            _context = context;
        }

        // GET: Product/Details/5
        [HttpGet]
        public async Task<IActionResult> Details(int? id)
        {
            if (id == null)
            {
                return NotFound();
            }

            var product = await _context.Products
                .Include(p => p.Reviews)
                .FirstOrDefaultAsync(p => p.Id == id);

            if (product == null)
            {
                return NotFound();
            }

            var reviews = product.Reviews
                .OrderByDescending(r => r.CreatedAt)
                .ToList();

            var averageRating = reviews.Any() ? reviews.Average(r => r.Rating) : 0;

            var viewModel = new ProductReviewViewModel
            {
                Product = product,
                Reviews = reviews,
                NewReview = new Review { ProductId = product.Id },
                AverageRating = Math.Round(averageRating, 1)
            };

            return View(viewModel);
        }

        // POST: Product/SubmitReview
        [HttpPost]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> SubmitReview(Review review)
        {
            if (ModelState.IsValid)
            {
                review.CreatedAt = DateTime.UtcNow;
                _context.Reviews.Add(review);
                await _context.SaveChangesAsync();
                TempData["SuccessMessage"] = "Your review has been submitted successfully!";
                return RedirectToAction(nameof(Details), new { id = review.ProductId });
            }

            // If validation fails, reload the product page with errors
            var product = await _context.Products
                .Include(p => p.Reviews)
                .FirstOrDefaultAsync(p => p.Id == review.ProductId);

            if (product == null)
            {
                return NotFound();
            }

            var reviews = product.Reviews
                .OrderByDescending(r => r.CreatedAt)
                .ToList();

            var averageRating = reviews.Any() ? reviews.Average(r => r.Rating) : 0;

            var viewModel = new ProductReviewViewModel
            {
                Product = product,
                Reviews = reviews,
                NewReview = review,
                AverageRating = Math.Round(averageRating, 1)
            };

            return View("Details", viewModel);
        }
    }
}

// Views/Product/Details.cshtml
@model ProductReviews.Models.ProductReviewViewModel
@using ProductReviews.Helpers

@{
    ViewData["Title"] = Model.Product.Name + " - Reviews";
}

<div class="container mt-4">
    <!-- Product Information -->
    <div class="card mb-4">
        <div class="card-body">
            <h1 class="card-title">@Model.Product.Name</h1>
            <p class="card-text">@Model.Product.Description</p>
            <h4 class="text-success">$@Model.Product.Price.ToString("F2")</h4>
            @if (Model.Reviews.Any())
            {
                <p class="text-muted">
                    Average Rating: <strong>@Model.AverageRating</strong> / 5
                    (@Model.Reviews.Count review@(Model.Reviews.Count != 1 ? "s" : ""))
                </p>
            }
        </div>
    </div>

    <!-- Success Message -->
    @if (TempData["SuccessMessage"] != null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @TempData["SuccessMessage"]
            <button type="button" class="btn-close" data-bs-dismiss="alert" aria-label="Close"></button>
        </div>
    }

    <!-- Submit Review Form -->
    <div class="card mb-4">
        <div class="card-header">
            <h3>Write a Review</h3>
        </div>
        <div class="card-body">
            <form asp-controller="Product" asp-action="SubmitReview" method="post">
                @Html.AntiForgeryToken()
                <input type="hidden" asp-for="NewReview.ProductId" />

                <div class="mb-3">
                    <label asp-for="NewReview.AuthorName" class="form-label">Your Name</label>
                    <input asp-for="NewReview.AuthorName" class="form-control" placeholder="Enter your name" />
                    <span asp-validation-for="NewReview.AuthorName" class="text-danger"></span>
                </div>

                <div class="mb-3">
                    <label asp-for="NewReview.Rating" class="form-label">Rating</label>
                    <select asp-for="NewReview.Rating" class="form-select" style="width: 200px;">
                        <option value="">Select a rating</option>
                        <option value="5">★★★★★ (5)</option>
                        <option value="4">★★★★☆ (4)</option>
                        <option value="3">★★★☆☆ (3)</option>
                        <option value="2">★★☆☆☆ (2)</option>
                        <option value="1">★☆☆☆☆ (1)</option>
                    </select>
                    <span asp-validation-for="NewReview.Rating" class="text-danger"></span>
                </div>

                <div class="mb-3">
                    <label asp-for="NewReview.Content" class="form-label">Your Review</label>
                    <textarea asp-for="NewReview.Content" class="form-control" rows="5"
                              placeholder="Write your review here. Use *text* for bold and _text_ for italic."></textarea>
                    <span asp-validation-for="NewReview.Content" class="text-danger"></span>
                    <small class="form-text text-muted">
                        Formatting tips: Use <code>*text*</code> for <strong>bold</strong> and <code>_text_</code> for <em>italic</em>.
                    </small>
                </div>

                <button type="submit" class="btn btn-primary">Submit Review</button>
            </form>
        </div>
    </div>

    <!-- Reviews List -->
    <div class="mb-4">
        <h3>Customer Reviews</h3>
        <hr />

        @if (!Model.Reviews.Any())
        {
            <div class="alert alert-info">
                No reviews yet. Be the first to review this product!
            </div>
        }
        else
        {
            @foreach (var review in Model.Reviews)
            {
                <div class="card mb-3">
                    <div class="card-body">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h5 class="card-title mb-0">@review.AuthorName</h5>
                            <small class="text-muted">@review.CreatedAt.ToString("MMMM dd, yyyy")</small>
                        </div>
                        <div class="mb-2">
                            @for (int i = 1; i <= 5; i++)
                            {
                                if (i <= review.Rating)
                                {
                                    <span class="text-warning">★</span>
                                }
                                else
                                {
                                    <span class="text-muted">☆</span>
                                }
                            }
                            <span class="ms-2 text-muted">(@review.Rating/5)</span>
                        </div>
                        <div class="card-text">
                            @Html.Raw(ReviewFormattingHelper.FormatReviewContent(review.Content))
                        </div>
                    </div>
                </div>
            }
        }
    </div>
</div>

@section Scripts {
    <partial name="_ValidationScriptsPartial" />
}

// Program.cs
using Microsoft.EntityFrameworkCore;
using ProductReviews.Data;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddControllersWithViews();

builder.Services.AddDbContext<ApplicationDbContext>(options =>
    options.UseSqlServer(builder.Configuration.GetConnectionString("DefaultConnection")));

var app = builder.Build();

if (!app.Environment.IsDevelopment())
{
    app.UseExceptionHandler("/Home/Error");
    app.UseHsts();
}

app.UseHttpsRedirection();
app.UseStaticFiles();
app.UseRouting();
app.UseAuthorization();

app.MapControllerRoute(
    name: "default",
    pattern: "{controller=Product}/{action=Details}/{id=1}");

using (var scope = app.Services.CreateScope())
{
    var dbContext = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
    dbContext.Database.EnsureCreated();
}

app.Run();